function initCountdown(){document.querySelectorAll(".timerevent").forEach(e=>{const o=e.getAttribute("data-inizio"),a=e.getAttribute("data-fine");if(!o)return;const s=new Date;s.setHours(0,0,0,0);const i=new Date(o);i.setHours(0,0,0,0);const r=a?new Date(a):new Date(o);r.setHours(0,0,0,0);let t="",n="";if(s>=i&&s<=r)t="🚀 CI SIAMO!",n="in-corso";else if(s<i){const e=Math.ceil((i-s)/(1e3*60*60*24));e===1?(t="⏰ DOMANI! Preparati!",n="urgente"):e<=3?(t=`🔥 SOLO ${e} GIORNI! Non aspettare!`,n="urgente"):e<=7?(t=`✨ Tra ${e} giorni ► Prenota la tua prova!`,n="presto"):e<=15?(t=`📅 Mancano ${e} giorni ► Prenota adesso`,n="normale"):(t=`🗓️ Dal ${new Date(o).toLocaleDateString("it-IT",{day:"numeric",month:"short"})}<br>📢 Iscrizioni Aperte`,n="futuro")}else{e.style.display="none";return}e.innerHTML=`<span class="countdown-${n}">${t}</span>`})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initCountdown):initCountdown()